import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I assign QA Admin scope?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/qa-admin-scope.md","filePath":"guide/recipes/admin/qa-admin-scope.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/admin/qa-admin-scope.md"};function i(r,e,c,l,d,p){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-assign-qa-admin-scope" tabindex="-1">How do I assign QA Admin scope? <a class="header-anchor" href="#how-do-i-assign-qa-admin-scope" aria-label="Permalink to &quot;How do I assign QA Admin scope?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> only</p></div><p>QA Admins are doubly scoped — a <strong>customer scope</strong> and an <strong>instance scope</strong>. They can only operate where <em>both</em> scopes intersect.</p><h2 id="at-invite-time" tabindex="-1">At invite time <a class="header-anchor" href="#at-invite-time" aria-label="Permalink to &quot;At invite time&quot;">​</a></h2><p>The scope pickers appear when you tick <strong>QA Admin</strong> on the <a href="./create-internal-user">invite form</a>. You must grant at least one customer <strong>and</strong> at least one instance.</p><h2 id="on-an-existing-user" tabindex="-1">On an existing user <a class="header-anchor" href="#on-an-existing-user" aria-label="Permalink to &quot;On an existing user&quot;">​</a></h2><ol><li>Open <strong>Internal Users</strong> and click the user.</li><li>Make sure they have the <strong>QA Admin</strong> role checked.</li><li><strong>Customer Scope</strong> — click <strong>Grant Customer</strong> and pick customers.</li><li><strong>Instance Scope</strong> — click <strong>Grant Instance</strong> and pick instances.</li><li>Revoke with the X on any granted chip.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>When the QA Admin runs an action — start a migration, create a tenant, open an instance — it succeeds only if the target falls within both scopes. The Console hides options outside scope so the UI doesn&#39;t tempt them with disabled actions.</p><div class="tip custom-block"><p class="custom-block-title">Typical setup</p><p>QA Admins are scoped to <strong>QA / sandbox</strong> customers and <strong>non-prod</strong> instances so they can run validation flows without ever touching prod data.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./account-manager-scope">How do I assign Account Manager scope?</a></li><li><a href="./create-internal-user">How do I create an internal user?</a></li></ul>',12)])])}const u=t(o,[["render",i]]);export{m as __pageData,u as default};
